public class App {
    static String safeDivide(String a, String b) {
        try {
            int numA = Integer.parseInt(a);
            int numB = Integer.parseInt(b);
            return String.valueOf(numA / numB);
        } catch (NumberFormatException e) {
            return "Error: invalid number";
        } catch (ArithmeticException e) {
            return "Error: division by zero";
        }
    }

    public static void main(String[] args) {
        System.out.println(safeDivide("10", "2"));
        System.out.println(safeDivide("10", "abc"));
        System.out.println(safeDivide("10", "0"));
    }
}

public class App {
    static void runQuery(String query, boolean fail) {
        System.out.println("Connection opened");
        try {
            if (fail) throw new RuntimeException("Query failed");
            System.out.println("Query executed: " + query);
        } catch (RuntimeException e) {
            System.out.println("Error: " + e.getMessage());
        } finally {
            System.out.println("Connection closed");
        }
    }

    public static void main(String[] args) {
        runQuery("SELECT * FROM users", false);
        System.out.println("---");
        runQuery("SELECT * FROM orders", true);
    }
}

