public class App {
    record Person(String name, int age, double salary) {
        public String toString() { return "Person: " + name + ", " + age + ", ₹" + salary; }
    }

    static String parsePerson(String csv) {
        String[] parts = csv.split(",");
        if (parts.length != 3) return "Error: Expected 3 fields";

        String name = parts[0].trim();
        int age;
        double salary;

        try {
            age = Integer.parseInt(parts[1].trim());
        } catch (NumberFormatException e) {
            return "Error: Age must be a valid integer";
        }

        try {
            salary = Double.parseDouble(parts[2].trim());
        } catch (NumberFormatException e) {
            return "Error: Salary must be a valid number";
        }

        return new Person(name, age, salary).toString();
    }

    public static void main(String[] args) {
        System.out.println(parsePerson("Aisha,28,75000"));
        System.out.println(parsePerson("Raj,notAnAge,85000"));
        System.out.println(parsePerson("Priya,25,"));
    }
}

public class App {
    static int retryParse(String[] attempts, int maxRetries) {
        for (int i = 0; i < Math.min(attempts.length, maxRetries); i++) {
            try {
                int result = Integer.parseInt(attempts[i]);
                System.out.println("Attempt " + (i + 1) + ": '" + attempts[i] + "' — success: " + result);
                return result;
            } catch (NumberFormatException e) {
                System.out.println("Attempt " + (i + 1) + ": '" + attempts[i] + "' — failed");
            }
        }
        return -1;  // all failed
    }

    public static void main(String[] args) {
        retryParse(new String[]{"abc", "def", "42", "99"}, 3);
    }
}

import java.util.*;

public class App {
    static String transfer(Map<String, Double> accounts,
                           String from, String to, String amountStr) {
        double amount;
        try {
            amount = Double.parseDouble(amountStr);
        } catch (NumberFormatException e) {
            return "Invalid amount format";
        }

        if (amount <= 0) return "Amount must be positive";
        if (!accounts.containsKey(from)) return "Account not found: " + from;
        if (!accounts.containsKey(to))   return "Account not found: " + to;

        double balance = accounts.get(from);
        if (balance < amount) return "Insufficient funds in " + from;

        accounts.put(from, balance - amount);
        accounts.put(to, accounts.get(to) + amount);
        return "Transfer complete";
    }

    public static void main(String[] args) {
        Map<String, Double> accounts = new HashMap<>();
        accounts.put("A001", 5000.0);
        accounts.put("A002", 1000.0);

        System.out.println(transfer(accounts, "A001", "A002", "2000"));
        System.out.println(transfer(accounts, "A001", "A002", "5000"));  // now only 3000
        System.out.println(transfer(accounts, "A001", "A002", "abc"));
        System.out.println(transfer(accounts, "A999", "A002", "100"));
    }
}

public class App {
    static void deepMethod() {
        System.out.println("deepMethod: throwing");
        Integer.parseInt("bad");  // throws NumberFormatException
    }

    static void middleMethod() {
        try {
            deepMethod();
        } catch (NumberFormatException e) {
            System.out.println("middleMethod: caught, rethrowing as RuntimeException");
            throw new RuntimeException("wrapped", e);  // wrap with cause
        }
    }

    static void topMethod() {
        try {
            middleMethod();
        } catch (RuntimeException e) {
            String causeName = e.getCause() != null
                ? e.getCause().getClass().getSimpleName()
                : "none";
            System.out.println("topMethod: caught RuntimeException: original cause was " + causeName);
        }
    }

    public static void main(String[] args) {
        topMethod();
    }
}

public class App {
    public static void main(String[] args) {
        String[] items = {"100", "200", "bad", "300", "0"};
        int processed = 0;

        System.out.println("Processor opened");
        try {
            for (String item : items) {
                try {
                    int val = Integer.parseInt(item);
                    int result = 1000 / val;  // ArithmeticException if val==0
                    System.out.println("Processed: " + val);
                    processed++;
                } catch (NumberFormatException e) {
                    System.out.println("Skipped invalid item: " + item);
                } catch (ArithmeticException e) {
                    System.out.println("Skipped invalid item: " + item + " (" + e.getMessage() + ")");
                }
            }
        } finally {
            System.out.println("Processor closed");
        }
        System.out.println("Total processed: " + processed);
    }
}

import java.util.*;

public class App {
    static List<String> validatePayment(String cardNum, String expiryYearStr, String cvvStr, String amountStr) {
        List<String> errors = new ArrayList<>();

        // Card number: 16 digits
        if (cardNum == null || !cardNum.matches("\\d{16}")) {
            errors.add("Card number must be exactly 16 digits");
        }

        // Expiry year
        try {
            int year = Integer.parseInt(expiryYearStr);
            if (year < 2024 || year > 2030) errors.add("Expiry year must be 2024-2030");
        } catch (NumberFormatException e) {
            errors.add("Expiry year must be a valid year");
        }

        // CVV: 3-digit int
        try {
            int cvv = Integer.parseInt(cvvStr);
            if (String.valueOf(cvv).length() != 3 || cvv < 0) errors.add("CVV must be a 3-digit number");
        } catch (NumberFormatException e) {
            errors.add("CVV must be a 3-digit number");
        }

        // Amount
        try {
            double amount = Double.parseDouble(amountStr);
            if (amount <= 0) errors.add("Amount must be positive");
        } catch (NumberFormatException e) {
            errors.add("Amount must be a valid number");
        }

        return errors;
    }

    public static void main(String[] args) {
        List<String> errors = validatePayment(
            "1234567890123456", "2028", "12x", "-500"
        );

        if (errors.isEmpty()) {
            System.out.println("Payment valid");
        } else {
            System.out.println("Errors:");
            for (String err : errors) System.out.println("- " + err);
        }
    }
}
